(function () {
	"use strict";

	function handleShowCartDropAction() {
		var el = this;
		var srcPanel = foseCart.util.getSourcePanel(el, foseCart.ACTION_SHOW_CART_DROP);
		if (!srcPanel) return;
		srcPanel.insertTray()
			.then(function(tray) {
				var data = srcPanel.data();
				var stash = srcPanel.stash();
				var term = data.server.srcdb;
				var item = data.server;
				if (stash.viewing) {
					item = stash.viewing;
				}
	
				var regSection = foseCart.user.getRegisteredSection(term, item.crn);
				var waitlistSection = foseCart.user.getWaitlistedSection(term, item.crn);
	
				var cartID = sam.cart.PRIMARY_CART_ID;
				if (sam.config.areCartsByCareer) {
					var acadCareer = regSection ? regSection.acadCareer : waitlistSection.acadCareer;
					var cartID = sam.cart.PRIMARY_CART_ID_PREFIX + acadCareer;
				}
	
				var cart = {
					id: cartID,
					name: sam.cart.name(cartID, term),
					term: term
				};
	
				var templateData = {
					term: term,
					item: item,
					client: data.client,
					id: tray.id,
					carts: [cart],
					config: foseConfig,
				}
	
				return fose.events.emit('tray.cart-drop.beforeRender', templateData)
					.then(function () {
						return tray.show(foseCart.util.pluginRender('trayCartDrop', templateData));
					});
			})
	}
	
	fose.actions.handle(
		foseCart.ACTION_SHOW_CART_DROP,
		handleShowCartDropAction
	);
})();

