// Define escxml for public site
function escxml (str) {
   if (!str || typeof str !== "string")
      return '';
   return str
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
}

