var brownTranscriptURL = 'https://selfservice.brown.edu/ss/swp_internal_acad_record.p_Stud_IAR';
var brownTextViewTranscript = 'VIEW TRANSCRIPT';

fose.events.on('panel.results.drawDone', function injectTranscriptButton(panel) {
	var panelData = panel.data();
	var clientData = panelData.client;
	if (!clientData.cart || !clientData.isPrimaryCart(clientData.cart)) return;

	var url = escxml(brownTranscriptURL) + '?authpin=' + encodeURIComponent(sam.auth.token);
	if ($(panel.element).find('.transcript-button').length) return;
	$(panel.element).find('.panel__foot .button-bar').prepend('<a href="' + url + '" target="_blank" class="btn transcript-button">' + escxml(brownTextViewTranscript) + '</a>');
});

(function injectPanelClass() {
	'use strict';

	fose.events.on('panel.results.drawDone', function(panel) {
		var data = panel.data();
		panel.element.classList.remove("cart");
		panel.element.classList.remove("cart--primary");
		if (!data.client.cart) return;

		panel.element.classList.add("cart");
		if (sam.cart.isPrimary(data.client.cart.id)) {
			panel.element.classList.add("cart--primary");
		}

		return Promise.resolve();
	});
})();


fose.events.on('panel.' + foseCart.PANEL_CART_SECTION_OPTIONS + '.drawDone', function (panel) {
	var stashData = panel.stash();
	$(panel.previous.element).find('.registration-options-edit, .cart-controls button').prop('disabled', true);
	$(panel.element).on('change', 'input, select', function () {
		stashData.changed = true;
	});
	$(panel.element).on('click', 'button[data-action="cart-add-from-options"]', function () {
		stashData.changed = false;
	});
});

